'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { collection, query, orderBy, onSnapshot, addDoc, deleteDoc, doc, serverTimestamp, Timestamp } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Job } from '@/types';
import { JobCard } from '@/components/jobs/JobCard';
import { CreateOpportunityModal, OpportunityFormData } from '@/components/modals/CreateOpportunityModal';
import { ConfirmDialog } from '@/components/modals/ConfirmDialog';
import { Briefcase, Plus } from 'lucide-react';

export default function JobsPage() {
    const { userData, loading: authLoading } = useAuth();
    const [jobs, setJobs] = useState<Job[]>([]);
    const [loading, setLoading] = useState(true);
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [deletingJobId, setDeletingJobId] = useState<string | null>(null);
    const [filterType, setFilterType] = useState<string>('all');

    useEffect(() => {
        if (!userData) {
            setLoading(false);
            return;
        }

        const jobsQuery = query(
            collection(db, 'opportunities'),
            orderBy('createdAt', 'desc')
        );

        const unsubscribe = onSnapshot(jobsQuery, (snapshot) => {
            const fetchedJobs = snapshot.docs.map(doc => ({
                id: doc.id,
                ...doc.data()
            })) as Job[];
            setJobs(fetchedJobs);
            setLoading(false);
        });

        return () => unsubscribe();
    }, [userData]);

    const handleCreateOpportunity = async (formData: OpportunityFormData) => {
        if (!userData) return;

        let expiresAt = null;
        if (!formData.isPermanent && formData.expiryDate) {
            const [year, month, day] = formData.expiryDate.split('-');
            const expiryDate = new Date(Date.UTC(parseInt(year), parseInt(month) - 1, parseInt(day), 23, 59, 59));
            expiresAt = Timestamp.fromDate(expiryDate);
        }

        await addDoc(collection(db, 'opportunities'), {
            title: formData.title,
            company: formData.company,
            type: formData.type,
            location: formData.location,
            description: formData.description,
            contact: formData.contact,
            postedByUid: userData.uid,
            postedByName: userData.name,
            postedByBatch: userData.batch,
            createdAt: serverTimestamp(),
            expiresAt: expiresAt
        });
    };

    const handleDeleteJob = async () => {
        if (!deletingJobId) return;
        await deleteDoc(doc(db, 'opportunities', deletingJobId));
        setDeletingJobId(null);
    };

    const filteredJobs = jobs.filter(job => {
        if (filterType === 'all') return true;
        return job.type === filterType;
    });

    const activeJobs = filteredJobs.filter(job => {
        if (!job.expiresAt) return true;
        const now = new Date();
        const expiryDate = job.expiresAt.toDate();
        return expiryDate > now;
    });

    if (authLoading || loading) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
            </div>
        );
    }

    if (!userData) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <p className="text-gray-600">Please log in to view job opportunities</p>
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto p-4">
            {/* Header */}
            <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-3">
                    <Briefcase className="w-8 h-8 text-blue-600" />
                    <h1 className="text-2xl font-bold">Job Opportunities</h1>
                </div>
                <button
                    onClick={() => setShowCreateModal(true)}
                    className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition"
                >
                    <Plus className="w-5 h-5" />
                    Post a Job
                </button>
            </div>

            {/* Filters */}
            <div className="flex gap-2 mb-6 overflow-x-auto pb-2">
                {['all', 'Full-time', 'Part-time', 'Freelance/Contract', 'Internship'].map((type) => (
                    <button
                        key={type}
                        onClick={() => setFilterType(type)}
                        className={`px-4 py-2 rounded-lg font-medium whitespace-nowrap transition ${filterType === type
                                ? 'bg-blue-600 text-white'
                                : 'bg-white text-gray-700 hover:bg-gray-100'
                            }`}
                    >
                        {type === 'all' ? 'All Jobs' : type}
                    </button>
                ))}
            </div>

            {/* Jobs List */}
            <div className="space-y-4">
                {activeJobs.length > 0 ? (
                    activeJobs.map(job => (
                        <JobCard
                            key={job.id}
                            job={job}
                            currentUser={userData}
                            onDelete={() => setDeletingJobId(job.id)}
                        />
                    ))
                ) : (
                    <div className="bg-white rounded-xl shadow-sm p-8 text-center">
                        <Briefcase className="w-16 h-16 text-gray-300 mx-auto mb-4" />
                        <p className="text-gray-500">No job opportunities available</p>
                        <button
                            onClick={() => setShowCreateModal(true)}
                            className="mt-4 text-blue-600 hover:text-blue-700 font-medium"
                        >
                            Post the first opportunity
                        </button>
                    </div>
                )}
            </div>

            {/* Modals */}
            <CreateOpportunityModal
                isOpen={showCreateModal}
                onClose={() => setShowCreateModal(false)}
                onSubmit={handleCreateOpportunity}
            />

            <ConfirmDialog
                isOpen={!!deletingJobId}
                onClose={() => setDeletingJobId(null)}
                onConfirm={handleDeleteJob}
                title="Delete Job Posting"
                message="Are you sure you want to delete this job posting?"
                confirmText="Delete"
                variant="danger"
            />
        </div>
    );
}

'use client';

import { useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import { Eye, EyeOff, Loader2, ArrowLeft } from 'lucide-react';
import Link from 'next/link';

export default function LoginPage() {
    const { signIn } = useAuth();
    const router = useRouter();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        if (!email.trim() || !password.trim()) {
            setError('Please fill in all fields');
            return;
        }

        setLoading(true);
        try {
            await signIn(email, password);
            router.push('/');
        } catch (err: any) {
            console.error('Login error:', err);
            setError(err.message || 'Invalid email or password');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-gradient-to-br from-blue-50 to-blue-100 flex items-center justify-center p-4">
            <div className="max-w-md w-full">
                {/* Back Button */}
                <Link href="/" className="inline-flex items-center gap-2 text-blue-600 hover:text-blue-700 mb-6 font-medium">
                    <ArrowLeft className="w-4 h-4" />
                    Back to Home
                </Link>

                {/* Card */}
                <div className="bg-white rounded-2xl shadow-xl p-8">
                    {/* Header */}
                    <div className="text-center mb-8">
                        <div className="w-16 h-16 bg-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
                            <span className="text-2xl font-bold text-white">LA</span>
                        </div>
                        <h1 className="text-3xl font-bold text-gray-900 mb-2">Welcome Back</h1>
                        <p className="text-gray-600">Sign in to your alumni account</p>
                    </div>

                    {/* Error Message */}
                    {error && (
                        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg">
                            <p className="text-sm text-red-600">{error}</p>
                        </div>
                    )}

                    {/* Form */}
                    <form onSubmit={handleSubmit} className="space-y-5">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">
                                Email Address
                            </label>
                            <input
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                placeholder="your.email@example.com"
                                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition"
                                disabled={loading}
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">
                                Password
                            </label>
                            <div className="relative">
                                <input
                                    type={showPassword ? 'text' : 'password'}
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    placeholder="Enter your password"
                                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition pr-12"
                                    disabled={loading}
                                />
                                <button
                                    type="button"
                                    onClick={() => setShowPassword(!showPassword)}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-700"
                                >
                                    {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                                </button>
                            </div>
                        </div>

                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full py-3 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700 transition disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            {loading ? (
                                <span className="flex items-center justify-center gap-2">
                                    <Loader2 className="w-5 h-5 animate-spin" />
                                    Signing in...
                                </span>
                            ) : (
                                'Sign In'
                            )}
                        </button>
                    </form>

                    {/* Divider */}
                    <div className="my-6 flex items-center gap-4">
                        <div className="flex-1 border-t border-gray-300"></div>
                        <span className="text-sm text-gray-500">or</span>
                        <div className="flex-1 border-t border-gray-300"></div>
                    </div>

                    {/* Sign Up Link */}
                    <div className="text-center">
                        <p className="text-gray-600">
                            Don't have an account?{' '}
                            <Link href="/signup" className="text-blue-600 hover:text-blue-700 font-semibold">
                                Sign Up
                            </Link>
                        </p>
                    </div>
                </div>

                {/* Footer */}
                <p className="text-center text-sm text-gray-600 mt-6">
                    ┬⌐ 2024 Loyola Alumni Association. All rights reserved.
                </p>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { collection, query, where, orderBy, onSnapshot, addDoc, serverTimestamp, doc, getDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Message, User } from '@/types';
import { getChatId, getSharedSecret, encryptMessage, decryptMessage } from '@/lib/encryption';
import { ArrowLeft, Send } from 'lucide-react';
import { useRouter, useParams } from 'next/navigation';

export default function PersonalChatPage() {
    const { userData } = useAuth();
    const params = useParams();
    const recipientId = params.userId as string;
    const [recipient, setRecipient] = useState<User | null>(null);
    const [messages, setMessages] = useState<Message[]>([]);
    const [newMessage, setNewMessage] = useState('');
    const [loading, setLoading] = useState(true);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const router = useRouter();

    // Fetch recipient info
    useEffect(() => {
        if (!recipientId) return;

        const fetchRecipient = async () => {
            const userDoc = await getDoc(doc(db, 'users', recipientId));
            if (userDoc.exists()) {
                setRecipient({ uid: userDoc.id, ...userDoc.data() } as User);
            }
        };

        fetchRecipient();
    }, [recipientId]);

    // Fetch messages
    useEffect(() => {
        if (!userData || !recipientId) return;

        const chatId = getChatId(userData.uid, recipientId);
        const messagesQuery = query(
            collection(db, 'chats', chatId, 'messages'),
            orderBy('createdAt', 'asc')
        );

        const unsubscribe = onSnapshot(messagesQuery, (snapshot) => {
            const sharedSecret = getSharedSecret(userData.uid, recipientId);
            const fetchedMessages = snapshot.docs.map(doc => {
                const data = doc.data();
                return {
                    id: doc.id,
                    ...data,
                    text: decryptMessage(data.text, sharedSecret)
                };
            }) as Message[];

            setMessages(fetchedMessages);
            setLoading(false);
        });

        return () => unsubscribe();
    }, [userData, recipientId]);

    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    const handleSendMessage = async () => {
        if (!newMessage.trim() || !userData || !recipientId) return;

        const chatId = getChatId(userData.uid, recipientId);
        const sharedSecret = getSharedSecret(userData.uid, recipientId);
        const encryptedText = encryptMessage(newMessage.trim(), sharedSecret);

        await addDoc(collection(db, 'chats', chatId, 'messages'), {
            text: encryptedText,
            senderId: userData.uid,
            recipientId: recipientId,
            createdAt: serverTimestamp(),
            read: false
        });

        setNewMessage('');
    };

    const handleKeyPress = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleSendMessage();
        }
    };

    if (!userData) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <p className="text-gray-600">Please log in to access chat</p>
            </div>
        );
    }

    if (!recipient) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
            </div>
        );
    }

    return (
        <div className="flex flex-col h-screen bg-gray-50">
            {/* Header */}
            <div className="bg-white border-b px-4 py-3 flex items-center gap-3">
                <button
                    onClick={() => router.back()}
                    className="p-2 hover:bg-gray-100 rounded-full transition"
                >
                    <ArrowLeft className="w-5 h-5" />
                </button>
                <img
                    src={recipient.profilePic || `https://placehold.co/40x40/EFEFEFF/3B82F6?text=${recipient.name.substring(0, 1)}`}
                    alt={recipient.name}
                    className="w-10 h-10 rounded-full"
                />
                <div>
                    <h2 className="font-semibold">{recipient.name}</h2>
                    <p className="text-sm text-gray-600">Batch of {recipient.batch}</p>
                </div>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {loading ? (
                    <div className="flex items-center justify-center h-full">
                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
                    </div>
                ) : messages.length > 0 ? (
                    <>
                        {messages.map(msg => (
                            <div
                                key={msg.id}
                                className={`flex ${msg.senderId === userData.uid ? 'justify-end' : 'justify-start'}`}
                            >
                                <div
                                    className={`max-w-[70%] rounded-2xl px-4 py-2 ${msg.senderId === userData.uid
                                            ? 'bg-blue-600 text-white'
                                            : 'bg-white text-gray-900'
                                        }`}
                                >
                                    <p className="whitespace-pre-wrap break-words">{msg.text}</p>
                                </div>
                            </div>
                        ))}
                        <div ref={messagesEndRef} />
                    </>
                ) : (
                    <div className="flex items-center justify-center h-full">
                        <p className="text-gray-500">No messages yet. Start the conversation!</p>
                    </div>
                )}
            </div>

            {/* Input */}
            <div className="bg-white border-t p-4">
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={newMessage}
                        onChange={(e) => setNewMessage(e.target.value)}
                        onKeyPress={handleKeyPress}
                        placeholder="Type a message..."
                        className="flex-1 px-4 py-2 border border-gray-300 rounded-full focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    />
                    <button
                        onClick={handleSendMessage}
                        disabled={!newMessage.trim()}
                        className="p-3 bg-blue-600 text-white rounded-full hover:bg-blue-700 transition disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        <Send className="w-5 h-5" />
                    </button>
                </div>
            </div>
        </div>
    );
}

