'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { collection, query, orderBy, onSnapshot, addDoc, updateDoc, deleteDoc, doc, serverTimestamp } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Post } from '@/types';
import { PostCard } from '@/components/feed/PostCard';
import { CreatePostModal } from '@/components/modals/CreatePostModal';
import { EditPostModal } from '@/components/modals/EditPostModal';
import { CommentModal } from '@/components/modals/CommentModal';
import { ConfirmDialog } from '@/components/modals/ConfirmDialog';
import { PenSquare } from 'lucide-react';
import Link from 'next/link';

export default function HomePage() {
  const { userData, loading: authLoading } = useAuth();
  const [posts, setPosts] = useState<Post[]>([]);
  const [loading, setLoading] = useState(true);
  const [showCreatePost, setShowCreatePost] = useState(false);
  const [editingPost, setEditingPost] = useState<Post | null>(null);
  const [commentingPost, setCommentingPost] = useState<Post | null>(null);
  const [deletingPostId, setDeletingPostId] = useState<string | null>(null);

  // Fetch posts from Firebase
  useEffect(() => {
    if (!userData) {
      setLoading(false);
      return;
    }

    const postsQuery = query(
      collection(db, 'posts'),
      orderBy('createdAt', 'desc')
    );

    const unsubscribe = onSnapshot(postsQuery, (snapshot) => {
      const fetchedPosts = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as Post[];
      setPosts(fetchedPosts);
      setLoading(false);
    });

    return () => unsubscribe();
  }, [userData]);

  const handleCreatePost = async (content: string, imageUrl?: string) => {
    if (!userData) return;

    await addDoc(collection(db, 'posts'), {
      authorUid: userData.uid,
      authorName: userData.name,
      authorBatch: userData.batch,
      authorProfilePic: userData.profilePic,
      content,
      imageUrl: imageUrl || '',
      likes: [],
      comments: [],
      createdAt: serverTimestamp()
    });
  };

  const handleUpdatePost = async (postId: string, newContent: string) => {
    const postRef = doc(db, 'posts', postId);
    await updateDoc(postRef, { content: newContent });
  };

  const handleLikePost = async (postId: string, isLiked: boolean) => {
    if (!userData) return;

    const postRef = doc(db, 'posts', postId);
    const post = posts.find(p => p.id === postId);
    if (!post) return;

    const likes = post.likes || [];
    const updatedLikes = isLiked
      ? likes.filter(uid => uid !== userData.uid)
      : [...likes, userData.uid];

    await updateDoc(postRef, { likes: updatedLikes });
  };

  const handleAddComment = async (text: string) => {
    if (!userData || !commentingPost) return;

    const postRef = doc(db, 'posts', commentingPost.id);
    const post = posts.find(p => p.id === commentingPost.id);
    if (!post) return;

    const newComment = {
      authorUid: userData.uid,
      authorName: userData.name,
      text,
      createdAt: new Date()
    };

    const updatedComments = [...(post.comments || []), newComment];
    await updateDoc(postRef, { comments: updatedComments });
  };

  const handleDeletePost = async () => {
    if (!deletingPostId) return;
    await deleteDoc(doc(db, 'posts', deletingPostId));
    setDeletingPostId(null);
  };

  if (authLoading || loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading...</p>
        </div>
      </div>
    );
  }

  if (!userData) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <h2 className="text-2xl font-bold mb-4">Welcome to Alumni Network</h2>
          <p className="text-gray-600 mb-6">Please log in to continue</p>
          <div className="space-x-4">
            <Link href="/login" className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700">
              Log In
            </Link>
            <Link href="/signup" className="px-6 py-2 border border-blue-600 text-blue-600 rounded-lg hover:bg-blue-50">
              Sign Up
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto p-4">
      {/* Create Post Button */}
      <div className="bg-white rounded-xl shadow-sm p-4 mb-4">
        <button
          onClick={() => setShowCreatePost(true)}
          className="w-full flex items-center gap-3 px-4 py-3 bg-gray-100 hover:bg-gray-200 rounded-lg transition text-left"
        >
          <img
            src={userData.profilePic || `https://placehold.co/40x40/EFEFEFF/003366?text=${userData.name.substring(0, 1)}`}
            alt={userData.name}
            className="w-10 h-10 rounded-full"
          />
          <span className="text-gray-500">What's on your mind, {userData.name.split(' ')[0]}?</span>
          <PenSquare className="w-5 h-5 ml-auto text-blue-600" />
        </button>
      </div>

      {/* Posts Feed */}
      <div className="space-y-4">
        {posts.length > 0 ? (
          posts.map(post => (
            <PostCard
              key={post.id}
              post={post}
              currentUser={userData}
              onLike={(isLiked) => handleLikePost(post.id, isLiked)}
              onComment={() => setCommentingPost(post)}
              onEdit={() => setEditingPost(post)}
              onDelete={() => setDeletingPostId(post.id)}
            />
          ))
        ) : (
          <div className="bg-white rounded-xl shadow-sm p-8 text-center">
            <p className="text-gray-500">No posts yet. Be the first to share something!</p>
          </div>
        )}
      </div>

      {/* Modals */}
      <CreatePostModal
        isOpen={showCreatePost}
        onClose={() => setShowCreatePost(false)}
        onSubmit={handleCreatePost}
        currentUser={userData}
      />

      {editingPost && (
        <EditPostModal
          isOpen={true}
          onClose={() => setEditingPost(null)}
          onSubmit={handleUpdatePost}
          post={editingPost}
        />
      )}

      {commentingPost && (
        <CommentModal
          isOpen={true}
          onClose={() => setCommentingPost(null)}
          onSubmit={handleAddComment}
          comments={commentingPost.comments || []}
          postAuthor={commentingPost.authorName}
        />
      )}

      <ConfirmDialog
        isOpen={!!deletingPostId}
        onClose={() => setDeletingPostId(null)}
        onConfirm={handleDeletePost}
        title="Delete Post"
        message="Are you sure you want to delete this post? This action cannot be undone."
        confirmText="Delete"
        variant="danger"
      />
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { collection, query, where, orderBy, onSnapshot, updateDoc, doc, getDocs } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Post } from '@/types';
import { PostCard } from '@/components/feed/PostCard';
import { EditProfileModal, ProfileFormData } from '@/components/modals/EditProfileModal';
import { ConfirmDialog } from '@/components/modals/ConfirmDialog';
import { uploadToImgbb } from '@/lib/imageUpload';
import { Pencil, LogOut, MapPin, Briefcase } from 'lucide-react';
import Link from 'next/link';

export default function ProfilePage() {
    const { userData, signOut, loading: authLoading } = useAuth();
    const [posts, setPosts] = useState<Post[]>([]);
    const [loading, setLoading] = useState(true);
    const [showEditProfile, setShowEditProfile] = useState(false);
    const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
    const [updating, setUpdating] = useState(false);

    useEffect(() => {
        if (!userData) {
            setLoading(false);
            return;
        }

        const postsQuery = query(
            collection(db, 'posts'),
            where('authorUid', '==', userData.uid),
            orderBy('createdAt', 'desc')
        );

        const unsubscribe = onSnapshot(postsQuery, (snapshot) => {
            const fetchedPosts = snapshot.docs.map(doc => ({
                id: doc.id,
                ...doc.data()
            })) as Post[];
            setPosts(fetchedPosts);
            setLoading(false);
        });

        return () => unsubscribe();
    }, [userData]);

    const handleUpdateProfile = async (formData: ProfileFormData, profilePicFile?: File | null, isRemovingPic?: boolean) => {
        if (!userData) return;

        setUpdating(true);
        try {
            const userRef = doc(db, 'users', userData.uid);
            const updates: any = {
                name: formData.name,
                profession: formData.profession,
                location: formData.location,
            };

            // Handle profile picture
            if (isRemovingPic) {
                updates.profilePic = `https://placehold.co/100x100/EFEFEFF/003366?text=${formData.name.substring(0, 2).toUpperCase()}`;
            } else if (profilePicFile) {
                const uploadedUrl = await uploadToImgbb(profilePicFile);
                if (uploadedUrl) {
                    updates.profilePic = uploadedUrl;
                }
            }

            // Update user document
            await updateDoc(userRef, updates);

            // Update profile info on all posts by this user
            const postsQuery = query(collection(db, 'posts'), where('authorUid', '==', userData.uid));
            const postsSnapshot = await getDocs(postsQuery);

            const updatePromises = postsSnapshot.docs.map(postDoc => {
                const postRef = doc(db, 'posts', postDoc.id);
                return updateDoc(postRef, {
                    authorName: updates.name,
                    ...(updates.profilePic && { authorProfilePic: updates.profilePic })
                });
            });

            await Promise.all(updatePromises);

            // Show success message
            alert('Profile updated successfully!');
        } catch (error) {
            console.error('Error updating profile:', error);
            alert('Failed to update profile. Please try again.');
        } finally {
            setUpdating(false);
        }
    };

    const handleLogout = async () => {
        await signOut();
        window.location.href = '/login';
    };

    if (authLoading || loading) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <div className="text-center">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
                    <p className="text-gray-600">Loading profile...</p>
                </div>
            </div>
        );
    }

    if (!userData) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <div className="text-center">
                    <p className="text-gray-600 mb-4">Please log in to view your profile</p>
                    <Link href="/login" className="text-blue-600 hover:text-blue-700 font-medium">
                        Go to Login
                    </Link>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-4xl mx-auto p-4">
            {/* Cover Photo Area */}
            <div className="bg-gradient-to-r from-blue-500 to-blue-700 h-48 rounded-t-xl"></div>

            {/* Profile Header */}
            <div className="bg-white rounded-b-xl shadow-sm p-6 -mt-20 relative">
                <div className="flex flex-col md:flex-row items-center md:items-end gap-6">
                    {/* Profile Picture */}
                    <div className="relative">
                        <img
                            src={userData.profilePic || `https://placehold.co/150x150/EFEFEFF/003366?text=${userData.name.substring(0, 1)}`}
                            alt={userData.name}
                            className="w-32 h-32 rounded-full border-4 border-white shadow-lg object-cover"
                        />
                    </div>

                    {/* User Info */}
                    <div className="flex-1 text-center md:text-left">
                        <h1 className="text-3xl font-bold text-gray-900">{userData.name}</h1>
                        <p className="text-lg text-gray-600 mt-1">Batch of {userData.batch}</p>

                        <div className="flex flex-col md:flex-row gap-3 mt-3 text-gray-700">
                            {userData.profession && (
                                <div className="flex items-center justify-center md:justify-start gap-2">
                                    <Briefcase className="w-4 h-4 text-blue-600" />
                                    <span>{userData.profession}</span>
                                </div>
                            )}
                            {userData.location && (
                                <div className="flex items-center justify-center md:justify-start gap-2">
                                    <MapPin className="w-4 h-4 text-blue-600" />
                                    <span>{userData.location}</span>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Edit Button */}
                    <button
                        onClick={() => setShowEditProfile(true)}
                        className="flex items-center gap-2 px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition font-medium shadow-sm"
                    >
                        <Pencil className="w-4 h-4" />
                        Edit Profile
                    </button>
                </div>

                {/* Stats */}
                <div className="grid grid-cols-3 gap-4 mt-6 pt-6 border-t">
                    <div className="text-center">
                        <p className="text-2xl font-bold text-blue-600">{posts.length}</p>
                        <p className="text-sm text-gray-600">Posts</p>
                    </div>
                    <div className="text-center">
                        <p className="text-2xl font-bold text-blue-600">{userData.connections?.length || 0}</p>
                        <p className="text-sm text-gray-600">Connections</p>
                    </div>
                    <div className="text-center">
                        <p className="text-2xl font-bold text-blue-600">{userData.groups?.length || 0}</p>
                        <p className="text-sm text-gray-600">Groups</p>
                    </div>
                </div>
            </div>

            {/* User Posts */}
            <div className="mt-6">
                <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                    <span>My Posts</span>
                    <span className="text-sm font-normal text-gray-500">({posts.length})</span>
                </h2>
                <div className="space-y-4">
                    {posts.length > 0 ? (
                        posts.map(post => (
                            <PostCard
                                key={post.id}
                                post={post}
                                currentUser={userData}
                                onLike={() => { /* no-op */ }}
                                onComment={() => { /* no-op */ }}
                            />
                        ))
                    ) : (
                        <div className="bg-white rounded-xl shadow-sm p-12 text-center">
                            <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
                                <Pencil className="w-8 h-8 text-gray-400" />
                            </div>
                            <p className="text-gray-500 text-lg mb-2">No posts yet</p>
                            <p className="text-gray-400 text-sm">Share your first post to get started!</p>
                            <Link
                                href="/"
                                className="inline-block mt-4 px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition font-medium"
                            >
                                Create Post
                            </Link>
                        </div>
                    )}
                </div>
            </div>

            {/* Logout Section */}
            <div className="flex gap-4 justify-center py-8">
                <button
                    onClick={() => setShowLogoutConfirm(true)}
                    className="flex items-center gap-2 px-6 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition border border-gray-300"
                >
                    <LogOut className="w-5 h-5" />
                    Log Out
                </button>
            </div>

            {/* Modals */}
            {updating && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
                    <div className="bg-white rounded-lg p-6 text-center">
                        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
                        <p className="text-gray-700">Updating profile...</p>
                    </div>
                </div>
            )}

            <EditProfileModal
                isOpen={showEditProfile}
                onClose={() => setShowEditProfile(false)}
                onSubmit={handleUpdateProfile}
                currentUser={userData}
            />

            <ConfirmDialog
                isOpen={showLogoutConfirm}
                onClose={() => setShowLogoutConfirm(false)}
                onConfirm={handleLogout}
                title="Log Out"
                message="Are you sure you want to log out?"
                confirmText="Log Out"
                variant="warning"
            />
        </div>
    );
}

'use client';

import { useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import { uploadToImgbb } from '@/lib/imageUpload';
import { Eye, EyeOff, Loader2, Camera, ArrowLeft } from 'lucide-react';
import Link from 'next/link';

export default function SignUpPage() {
    const { signUp, error, clearError } = useAuth();
    const router = useRouter();
    const [loading, setLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: '',
        batch: new Date().getFullYear(),
        profession: '',
        location: '',
    });
    const [profilePicFile, setProfilePicFile] = useState<File | null>(null);
    const [previewUrl, setPreviewUrl] = useState<string>('');

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            // Validate file size (max 5MB)
            if (file.size > 5 * 1024 * 1024) {
                alert('Image size should be less than 5MB');
                return;
            }

            // Validate file type
            if (!file.type.startsWith('image/')) {
                alert('Please select an image file');
                return;
            }

            setProfilePicFile(file);
            setPreviewUrl(URL.createObjectURL(file));
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        clearError();

        try {
            let profilePicUrl = '';
            if (profilePicFile) {
                profilePicUrl = await uploadToImgbb(profilePicFile) || '';
            }

            await signUp(formData.email, formData.password, {
                name: formData.name,
                batch: formData.batch,
                profession: formData.profession,
                location: formData.location,
                profilePic: profilePicUrl || `https://placehold.co/100x100/EFEFEFF/003366?text=${formData.name.substring(0, 2).toUpperCase()}`,
            });

            router.push('/');
        } catch (err) {
            console.error('Sign up failed:', err);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-gradient-to-br from-blue-50 to-blue-100 flex items-center justify-center p-4">
            <div className="max-w-md w-full">
                {/* Back Button */}
                <Link href="/login" className="inline-flex items-center gap-2 text-blue-600 hover:text-blue-700 mb-6 font-medium">
                    <ArrowLeft className="w-4 h-4" />
                    Back to Login
                </Link>

                {/* Card */}
                <div className="bg-white rounded-2xl shadow-xl p-8">
                    {/* Header */}
                    <div className="text-center mb-8">
                        <div className="w-16 h-16 bg-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
                            <span className="text-2xl font-bold text-white">LA</span>
                        </div>
                        <h1 className="text-3xl font-bold text-gray-900 mb-2">Join Alumni Network</h1>
                        <p className="text-gray-600">Create your account to connect with fellow alumni</p>
                    </div>

                    {/* Error Message */}
                    {error && (
                        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg">
                            <p className="text-sm text-red-600">{error}</p>
                        </div>
                    )}

                    {/* Form */}
                    <form onSubmit={handleSubmit} className="space-y-4">
                        {/* Profile Picture */}
                        <div className="flex flex-col items-center mb-6">
                            <div className="relative group">
                                <div className="w-24 h-24 rounded-full overflow-hidden bg-gray-200 border-4 border-gray-100 shadow-md">
                                    {previewUrl ? (
                                        <img src={previewUrl} alt="Preview" className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center text-gray-400">
                                            <svg className="w-12 h-12" fill="currentColor" viewBox="0 0 20 20">
                                                <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
                                            </svg>
                                        </div>
                                    )}
                                </div>
                                {/* Camera overlay */}
                                <label className="absolute inset-0 flex items-center justify-center bg-black bg-opacity-40 rounded-full opacity-0 group-hover:opacity-100 transition cursor-pointer">
                                    <Camera className="w-8 h-8 text-white" />
                                    <input type="file" accept="image/*" onChange={handleFileChange} className="hidden" />
                                </label>
                            </div>
                            <label className="mt-3 cursor-pointer text-blue-600 hover:text-blue-700 text-sm font-medium">
                                Upload Photo (Optional)
                                <input type="file" accept="image/*" onChange={handleFileChange} className="hidden" />
                            </label>
                            <p className="text-xs text-gray-500 mt-1">Max size: 5MB</p>
                        </div>

                        {/* Name */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Full Name <span className="text-red-500">*</span>
                            </label>
                            <input
                                type="text"
                                placeholder="John Doe"
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition"
                                required
                            />
                        </div>

                        {/* Email */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Email Address <span className="text-red-500">*</span>
                            </label>
                            <input
                                type="email"
                                placeholder="your.email@example.com"
                                value={formData.email}
                                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition"
                                required
                            />
                        </div>

                        {/* Password */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Password <span className="text-red-500">*</span>
                            </label>
                            <div className="relative">
                                <input
                                    type={showPassword ? 'text' : 'password'}
                                    placeholder="Minimum 6 characters"
                                    value={formData.password}
                                    onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition pr-12"
                                    required
                                    minLength={6}
                                />
                                <button
                                    type="button"
                                    onClick={() => setShowPassword(!showPassword)}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-700"
                                >
                                    {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                                </button>
                            </div>
                        </div>

                        {/* Batch Year */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Batch Year <span className="text-red-500">*</span>
                            </label>
                            <input
                                type="number"
                                placeholder="e.g., 2020"
                                value={formData.batch}
                                onChange={(e) => setFormData({ ...formData, batch: parseInt(e.target.value) })}
                                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition"
                                required
                                min={1950}
                                max={new Date().getFullYear()}
                            />
                        </div>

                        {/* Profession */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Profession <span className="text-red-500">*</span>
                            </label>
                            <input
                                type="text"
                                placeholder="e.g., Software Engineer"
                                value={formData.profession}
                                onChange={(e) => setFormData({ ...formData, profession: e.target.value })}
                                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition"
                                required
                            />
                        </div>

                        {/* Location */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Location <span className="text-red-500">*</span>
                            </label>
                            <input
                                type="text"
                                placeholder="e.g., New York, USA"
                                value={formData.location}
                                onChange={(e) => setFormData({ ...formData, location: e.target.value })}
                                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition"
                                required
                            />
                        </div>

                        {/* Submit Button */}
                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full py-3 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700 transition disabled:opacity-50 disabled:cursor-not-allowed mt-6"
                        >
                            {loading ? (
                                <span className="flex items-center justify-center gap-2">
                                    <Loader2 className="w-5 h-5 animate-spin" />
                                    Creating Account...
                                </span>
                            ) : (
                                'Create Account'
                            )}
                        </button>
                    </form>

                    {/* Login Link */}
                    <div className="text-center mt-6">
                        <p className="text-gray-600">
                            Already have an account?{' '}
                            <Link href="/login" className="text-blue-600 hover:text-blue-700 font-semibold">
                                Log In
                            </Link>
                        </p>
                    </div>
                </div>

                {/* Footer */}
                <p className="text-center text-sm text-gray-600 mt-6">
                    ┬⌐ 2024 Loyola Alumni Association. All rights reserved.
                </p>
            </div>
        </div>
    );
}

'use client';

import { Post, User } from '@/types';
import { Heart, MessageCircle, Share2, MoreHorizontal, Pencil, Trash2 } from 'lucide-react';
import { useState } from 'react';

interface PostCardProps {
    post: Post;
    currentUser: User;
    onLike: (isLiked: boolean) => void;
    onComment: () => void;
    onEdit?: () => void;
    onDelete?: () => void;
}

export const PostCard: React.FC<PostCardProps> = ({
    post,
    currentUser,
    onLike,
    onComment,
    onEdit,
    onDelete,
}) => {
    const [showMenu, setShowMenu] = useState(false);
    const isLiked = post.likes?.includes(currentUser.uid) || false;
    const isOwnPost = post.authorUid === currentUser.uid;

    const formatTimestamp = (timestamp: any) => {
        if (!timestamp) return 'Just now';
        const date = timestamp.toDate ? timestamp.toDate() : new Date(timestamp);
        const now = new Date();
        const diffInMs = now.getTime() - date.getTime();
        const diffInMins = Math.floor(diffInMs / 60000);
        const diffInHours = Math.floor(diffInMs / 3600000);
        const diffInDays = Math.floor(diffInMs / 86400000);

        if (diffInMins < 1) return 'Just now';
        if (diffInMins < 60) return `${diffInMins}m ago`;
        if (diffInHours < 24) return `${diffInHours}h ago`;
        if (diffInDays < 7) return `${diffInDays}d ago`;
        return date.toLocaleDateString();
    };

    return (
        <div className="bg-white rounded-xl shadow-sm p-4">
            {/* Header */}
            <div className="flex items-start justify-between mb-3">
                <div className="flex items-center gap-3">
                    <img
                        src={post.authorProfilePic || `https://placehold.co/40x40/EFEFEFF/003366?text=${post.authorName.substring(0, 1)}`}
                        alt={post.authorName}
                        className="w-10 h-10 rounded-full"
                    />
                    <div>
                        <h3 className="font-semibold text-gray-900">{post.authorName}</h3>
                        <p className="text-sm text-gray-500">
                            Batch of {post.authorBatch} ΓÇó {formatTimestamp(post.createdAt)}
                        </p>
                    </div>
                </div>

                {isOwnPost && (
                    <div className="relative">
                        <button
                            onClick={() => setShowMenu(!showMenu)}
                            className="p-2 hover:bg-gray-100 rounded-full transition"
                        >
                            <MoreHorizontal className="w-5 h-5 text-gray-600" />
                        </button>

                        {showMenu && (
                            <div className="absolute right-0 mt-2 w-48 bg-white rounded-lg shadow-lg border border-gray-200 py-1 z-10">
                                {onEdit && (
                                    <button
                                        onClick={() => {
                                            onEdit();
                                            setShowMenu(false);
                                        }}
                                        className="w-full px-4 py-2 text-left hover:bg-gray-100 flex items-center gap-2"
                                    >
                                        <Pencil className="w-4 h-4" />
                                        Edit Post
                                    </button>
                                )}
                                {onDelete && (
                                    <button
                                        onClick={() => {
                                            onDelete();
                                            setShowMenu(false);
                                        }}
                                        className="w-full px-4 py-2 text-left hover:bg-gray-100 flex items-center gap-2 text-red-600"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                        Delete Post
                                    </button>
                                )}
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* Content */}
            <p className="text-gray-800 mb-3 whitespace-pre-wrap">{post.content}</p>

            {/* Image */}
            {post.imageUrl && (
                <img
                    src={post.imageUrl}
                    alt="Post"
                    className="w-full rounded-lg mb-3"
                />
            )}

            {/* Stats */}
            <div className="flex items-center justify-between text-sm text-gray-500 mb-3 pt-2 border-t">
                <span>{post.likes?.length || 0} likes</span>
                <span>{post.comments?.length || 0} comments</span>
            </div>

            {/* Actions */}
            <div className="flex items-center gap-2 pt-2 border-t">
                <button
                    onClick={() => onLike(isLiked)}
                    className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg transition ${isLiked
                            ? 'text-red-600 bg-red-50 hover:bg-red-100'
                            : 'text-gray-600 hover:bg-gray-100'
                        }`}
                >
                    <Heart className={`w-5 h-5 ${isLiked ? 'fill-current' : ''}`} />
                    <span className="font-medium">Like</span>
                </button>

                <button
                    onClick={onComment}
                    className="flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-gray-600 hover:bg-gray-100 transition"
                >
                    <MessageCircle className="w-5 h-5" />
                    <span className="font-medium">Comment</span>
                </button>

                <button className="flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-gray-600 hover:bg-gray-100 transition">
                    <Share2 className="w-5 h-5" />
                    <span className="font-medium">Share</span>
                </button>
            </div>
        </div>
    );
};

'use client';

import { Job, User } from '@/types';
import { MapPin, Briefcase, Calendar, Trash2 } from 'lucide-react';

interface JobCardProps {
    job: Job;
    currentUser: User;
    onDelete?: () => void;
}

export const JobCard: React.FC<JobCardProps> = ({ job, currentUser, onDelete }) => {
    const isOwnJob = job.postedByUid === currentUser.uid;

    const formatDate = (timestamp: any) => {
        if (!timestamp) return '';
        const date = timestamp.toDate ? timestamp.toDate() : new Date(timestamp);
        return date.toLocaleDateString();
    };

    const typeColors: Record<string, string> = {
        'Full-time': 'bg-green-100 text-green-800',
        'Part-time': 'bg-blue-100 text-blue-800',
        'Freelance/Contract': 'bg-purple-100 text-purple-800',
        'Internship': 'bg-yellow-100 text-yellow-800',
    };

    return (
        <div className="bg-white rounded-xl shadow-sm p-6 hover:shadow-md transition">
            <div className="flex items-start justify-between mb-4">
                <div className="flex-1">
                    <h3 className="text-xl font-semibold text-gray-900 mb-2">{job.title}</h3>
                    <p className="text-lg text-gray-700 mb-2">{job.company}</p>
                    <div className="flex flex-wrap gap-2 mb-3">
                        <span className={`px-3 py-1 rounded-full text-sm font-medium ${typeColors[job.type] || 'bg-gray-100 text-gray-800'}`}>
                            {job.type}
                        </span>
                        {job.location && (
                            <span className="flex items-center gap-1 text-sm text-gray-600">
                                <MapPin className="w-4 h-4" />
                                {job.location}
                            </span>
                        )}
                    </div>
                </div>

                {isOwnJob && onDelete && (
                    <button
                        onClick={onDelete}
                        className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition"
                        title="Delete job posting"
                    >
                        <Trash2 className="w-5 h-5" />
                    </button>
                )}
            </div>

            <p className="text-gray-700 mb-4 whitespace-pre-wrap">{job.description}</p>

            <div className="flex items-center justify-between pt-4 border-t">
                <div className="text-sm text-gray-500">
                    <p>Posted by {job.postedByName} (Batch {job.postedByBatch})</p>
                    <p className="flex items-center gap-1 mt-1">
                        <Calendar className="w-4 h-4" />
                        {formatDate(job.createdAt)}
                        {job.expiresAt && ` ΓÇó Expires ${formatDate(job.expiresAt)}`}
                    </p>
                </div>

                {job.contact && (
                    <a
                        href={job.contact.includes('@') ? `mailto:${job.contact}` : job.contact}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition font-medium"
                    >
                        Apply Now
                    </a>
                )}
            </div>
        </div>
    );
};

'use client';

import { useState } from 'react';
import { X, Send } from 'lucide-react';
import { Comment } from '@/types';

interface CommentModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSubmit: (text: string) => Promise<void>;
    comments: Comment[];
    postAuthor: string;
}

export const CommentModal: React.FC<CommentModalProps> = ({
    isOpen,
    onClose,
    onSubmit,
    comments,
    postAuthor,
}) => {
    const [commentText, setCommentText] = useState('');
    const [loading, setLoading] = useState(false);

    if (!isOpen) return null;

    const handleSubmit = async () => {
        if (!commentText.trim()) return;

        setLoading(true);
        try {
            await onSubmit(commentText);
            setCommentText('');
        } catch (error) {
            console.error('Error adding comment:', error);
            alert('Failed to add comment. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const formatDate = (date: Date | any) => {
        if (date?.toDate) {
            return date.toDate().toLocaleDateString();
        }
        return new Date(date).toLocaleDateString();
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl max-w-2xl w-full max-h-[80vh] flex flex-col">
                {/* Header */}
                <div className="flex items-center justify-between p-4 border-b">
                    <h2 className="text-xl font-semibold">Comments</h2>
                    <button
                        onClick={onClose}
                        className="p-2 hover:bg-gray-100 rounded-full transition"
                    >
                        <X className="w-5 h-5" />
                    </button>
                </div>

                {/* Comments List */}
                <div className="flex-1 overflow-y-auto p-4 space-y-4">
                    {comments.length > 0 ? (
                        comments.map((comment, index) => (
                            <div key={index} className="flex gap-3">
                                <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center flex-shrink-0">
                                    <span className="text-sm font-semibold text-blue-600">
                                        {comment.authorName.substring(0, 1)}
                                    </span>
                                </div>
                                <div className="flex-1">
                                    <div className="bg-gray-100 rounded-lg p-3">
                                        <p className="font-semibold text-sm">{comment.authorName}</p>
                                        <p className="text-gray-800 mt-1">{comment.text}</p>
                                    </div>
                                    <p className="text-xs text-gray-500 mt-1">
                                        {formatDate(comment.createdAt)}
                                    </p>
                                </div>
                            </div>
                        ))
                    ) : (
                        <p className="text-center text-gray-500 py-8">No comments yet. Be the first to comment!</p>
                    )}
                </div>

                {/* Comment Input */}
                <div className="p-4 border-t">
                    <div className="flex gap-2">
                        <input
                            type="text"
                            value={commentText}
                            onChange={(e) => setCommentText(e.target.value)}
                            onKeyPress={(e) => e.key === 'Enter' && handleSubmit()}
                            placeholder="Write a comment..."
                            className="flex-1 px-4 py-2 border border-gray-300 rounded-full focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        />
                        <button
                            onClick={handleSubmit}
                            disabled={!commentText.trim() || loading}
                            className="p-2 bg-blue-600 text-white rounded-full hover:bg-blue-700 transition disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            <Send className="w-5 h-5" />
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

'use client';

import { useState } from 'react';
import { X } from 'lucide-react';

interface CreateOpportunityModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSubmit: (data: OpportunityFormData) => Promise<void>;
}

export interface OpportunityFormData {
    title: string;
    company: string;
    type: 'Full-time' | 'Part-time' | 'Freelance/Contract' | 'Internship';
    location: string;
    description: string;
    contact: string;
    expiryDate?: string;
    isPermanent: boolean;
}

export const CreateOpportunityModal: React.FC<CreateOpportunityModalProps> = ({
    isOpen,
    onClose,
    onSubmit,
}) => {
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState<OpportunityFormData>({
        title: '',
        company: '',
        type: 'Full-time',
        location: '',
        description: '',
        contact: '',
        expiryDate: '',
        isPermanent: false,
    });

    if (!isOpen) return null;

    const handleSubmit = async () => {
        if (!formData.title || !formData.company || !formData.description) {
            alert('Please fill in all required fields');
            return;
        }

        setLoading(true);
        try {
            await onSubmit(formData);
            // Reset form
            setFormData({
                title: '',
                company: '',
                type: 'Full-time',
                location: '',
                description: '',
                contact: '',
                expiryDate: '',
                isPermanent: false,
            });
            onClose();
        } catch (error) {
            console.error('Error creating opportunity:', error);
            alert('Failed to create opportunity. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto">
